      "title": "Puerto Rico status and democratic representation review [Outside scope]",
      "full_title": "HOR-021: Puerto Rico status and democratic representation review [Outside scope]",
      "issue_state": "Closed",
      "development_level": "Closed",
      "workflow_status": "Closed",
      "area": "Unassigned",
      "priority": "Unassigned",
      "release_blocker": "Unassigned",
