      "number": 303,
      "title": "Safeguards for Class-Based Presidential Entry Suspensions",
      "full_title": "HOR-041: Safeguards for Class-Based Presidential Entry Suspensions",
      "issue_state": "Open",
      "development_level": "Candidate",
      "workflow_status": "Development",
      "area": "RIGHTS",
      "priority": "Medium",
      "release_blocker": "Later",
